		delete(backRepoMesh.Map_MeshPtr_MeshDBID, mesh)
		delete(backRepoMesh.Map_MeshDBID_MeshDB, meshID)
		delete(backRepoMesh.Map_MeshDBID_MeshPtr, meshID)
