// Backup generates a json file from a slice of all MeshDB instances in the backrepo
func (backRepoMesh *BackRepoMeshStruct) Backup(dirPath string) {

	filename := filepath.Join(dirPath, "MeshDB.json")

	// organize the map into an array with increasing IDs, in order to have repoductible
	// backup file
	forBackup := make([]*MeshDB, 0)
	for _, meshDB := range backRepoMesh.Map_MeshDBID_MeshDB {
		forBackup = append(forBackup, meshDB)
	}

	sort.Slice(forBackup[:], func(i, j int) bool {
		return forBackup[i].ID < forBackup[j].ID
	})

	file, err := json.MarshalIndent(forBackup, "", " ")

	if err != nil {
		log.Fatal("Cannot json Mesh ", filename, " ", err.Error())
	}

	err = ioutil.WriteFile(filename, file, 0644)
	if err != nil {
		log.Fatal("Cannot write the json Mesh file", err.Error())
	}
}

// Backup generates a json file from a slice of all MeshDB instances in the backrepo
func (backRepoMesh *BackRepoMeshStruct) BackupXL(file *xlsx.File) {

	// organize the map into an array with increasing IDs, in order to have repoductible
	// backup file
	forBackup := make([]*MeshDB, 0)
	for _, meshDB := range backRepoMesh.Map_MeshDBID_MeshDB {
		forBackup = append(forBackup, meshDB)
	}

	sort.Slice(forBackup[:], func(i, j int) bool {
		return forBackup[i].ID < forBackup[j].ID
	})

	sh, err := file.AddSheet("Mesh")
	if err != nil {
		log.Fatal("Cannot add XL file", err.Error())
	}
	_ = sh

	row := sh.AddRow()
	row.WriteSlice(&Mesh_Fields, -1)
	for _, meshDB := range forBackup {

		var meshWOP MeshWOP
		meshDB.CopyBasicFieldsToMeshWOP(&meshWOP)

		row := sh.AddRow()
		row.WriteStruct(&meshWOP, -1)
	}
}

// RestoreXL from the "Mesh" sheet all MeshDB instances
func (backRepoMesh *BackRepoMeshStruct) RestoreXLPhaseOne(file *xlsx.File) {

	// resets the map
	BackRepoMeshid_atBckpTime_newID = make(map[uint]uint)

	sh, ok := file.Sheet["Mesh"]
	_ = sh
	if !ok {
		log.Fatal(errors.New("sheet not found"))
	}

	// log.Println("Max row is", sh.MaxRow)
	err := sh.ForEachRow(backRepoMesh.rowVisitorMesh)
	if err != nil {
		log.Fatal("Err=", err)
	}
}

func (backRepoMesh *BackRepoMeshStruct) rowVisitorMesh(row *xlsx.Row) error {

	log.Printf("row line %d\n", row.GetCoordinate())
	log.Println(row)

	// skip first line
	if row.GetCoordinate() > 0 {
		var meshWOP MeshWOP
		row.ReadStruct(&meshWOP)

		// add the unmarshalled struct to the stage
		meshDB := new(MeshDB)
		meshDB.CopyBasicFieldsFromMeshWOP(&meshWOP)

		meshDB_ID_atBackupTime := meshDB.ID
		meshDB.ID = 0
		_, err := backRepoMesh.db.Create(meshDB)
		if err != nil {
			log.Fatal(err)
		}
		backRepoMesh.Map_MeshDBID_MeshDB[meshDB.ID] = meshDB
		BackRepoMeshid_atBckpTime_newID[meshDB_ID_atBackupTime] = meshDB.ID
	}
	return nil
}

// RestorePhaseOne read the file "MeshDB.json" in dirPath that stores an array
// of MeshDB and stores it in the database
// the map BackRepoMeshid_atBckpTime_newID is updated accordingly
func (backRepoMesh *BackRepoMeshStruct) RestorePhaseOne(dirPath string) {

	// resets the map
	BackRepoMeshid_atBckpTime_newID = make(map[uint]uint)

	filename := filepath.Join(dirPath, "MeshDB.json")
	jsonFile, err := os.Open(filename)
	// if we os.Open returns an error then handle it
	if err != nil {
		log.Fatal("Cannot restore/open the json Mesh file", filename, " ", err.Error())
	}

	// read our opened jsonFile as a byte array.
	byteValue, _ := ioutil.ReadAll(jsonFile)

	var forRestore []*MeshDB

	err = json.Unmarshal(byteValue, &forRestore)

	// fill up Map_MeshDBID_MeshDB
	for _, meshDB := range forRestore {

		meshDB_ID_atBackupTime := meshDB.ID
		meshDB.ID = 0
		_, err := backRepoMesh.db.Create(meshDB)
		if err != nil {
			log.Fatal(err)
		}
		backRepoMesh.Map_MeshDBID_MeshDB[meshDB.ID] = meshDB
		BackRepoMeshid_atBckpTime_newID[meshDB_ID_atBackupTime] = meshDB.ID
	}

	if err != nil {
		log.Fatal("Cannot restore/unmarshall json Mesh file", err.Error())
	}
}

// RestorePhaseTwo uses all map BackRepo<Mesh>id_atBckpTime_newID
// to compute new index
func (backRepoMesh *BackRepoMeshStruct) RestorePhaseTwo() {

	for _, meshDB := range backRepoMesh.Map_MeshDBID_MeshDB {

		// next line of code is to avert unused variable compilation error
		_ = meshDB

		// insertion point for reindexing pointers encoding
		// reindexing MeshMaterialBasic field
		if meshDB.MeshMaterialBasicID.Int64 != 0 {
			meshDB.MeshMaterialBasicID.Int64 = int64(BackRepoMeshMaterialBasicid_atBckpTime_newID[uint(meshDB.MeshMaterialBasicID.Int64)])
			meshDB.MeshMaterialBasicID.Valid = true
		}

		// reindexing MeshPhysicalMaterial field
		if meshDB.MeshPhysicalMaterialID.Int64 != 0 {
			meshDB.MeshPhysicalMaterialID.Int64 = int64(BackRepoMeshPhysicalMaterialid_atBckpTime_newID[uint(meshDB.MeshPhysicalMaterialID.Int64)])
			meshDB.MeshPhysicalMaterialID.Valid = true
		}

		// reindexing CylinderGeometry field
		if meshDB.CylinderGeometryID.Int64 != 0 {
			meshDB.CylinderGeometryID.Int64 = int64(BackRepoCylinderGeometryid_atBckpTime_newID[uint(meshDB.CylinderGeometryID.Int64)])
			meshDB.CylinderGeometryID.Valid = true
		}

		// reindexing BoxGeometry field
		if meshDB.BoxGeometryID.Int64 != 0 {
			meshDB.BoxGeometryID.Int64 = int64(BackRepoBoxGeometryid_atBckpTime_newID[uint(meshDB.BoxGeometryID.Int64)])
			meshDB.BoxGeometryID.Valid = true
		}

		// reindexing SphereGeometry field
		if meshDB.SphereGeometryID.Int64 != 0 {
			meshDB.SphereGeometryID.Int64 = int64(BackRepoSphereGeometryid_atBckpTime_newID[uint(meshDB.SphereGeometryID.Int64)])
			meshDB.SphereGeometryID.Valid = true
		}

		// reindexing TorusGeometry field
		if meshDB.TorusGeometryID.Int64 != 0 {
			meshDB.TorusGeometryID.Int64 = int64(BackRepoTorusGeometryid_atBckpTime_newID[uint(meshDB.TorusGeometryID.Int64)])
			meshDB.TorusGeometryID.Valid = true
		}

		// reindexing PlaneGeometry field
		if meshDB.PlaneGeometryID.Int64 != 0 {
			meshDB.PlaneGeometryID.Int64 = int64(BackRepoPlaneGeometryid_atBckpTime_newID[uint(meshDB.PlaneGeometryID.Int64)])
			meshDB.PlaneGeometryID.Valid = true
		}

		// reindexing TubeGeometry field
		if meshDB.TubeGeometryID.Int64 != 0 {
			meshDB.TubeGeometryID.Int64 = int64(BackRepoTubeGeometryid_atBckpTime_newID[uint(meshDB.TubeGeometryID.Int64)])
			meshDB.TubeGeometryID.Valid = true
		}

		// reindexing ExtrudeGeometry field
		if meshDB.ExtrudeGeometryID.Int64 != 0 {
			meshDB.ExtrudeGeometryID.Int64 = int64(BackRepoExtrudeGeometryid_atBckpTime_newID[uint(meshDB.ExtrudeGeometryID.Int64)])
			meshDB.ExtrudeGeometryID.Valid = true
		}

		// update databse with new index encoding
		db, _ := backRepoMesh.db.Model(meshDB)
		_, err := db.Updates(*meshDB)
		if err != nil {
			log.Fatal(err)
		}
	}

}

// BackRepoMesh.ResetReversePointers commits all staged instances of Mesh to the BackRepo
// Phase Two is the update of instance with the field in the database
func (backRepoMesh *BackRepoMeshStruct) ResetReversePointers(backRepo *BackRepoStruct) (Error error) {

	for idx, mesh := range backRepoMesh.Map_MeshDBID_MeshPtr {
		backRepoMesh.ResetReversePointersInstance(backRepo, idx, mesh)
	}

	return
}

func (backRepoMesh *BackRepoMeshStruct) ResetReversePointersInstance(backRepo *BackRepoStruct, idx uint, mesh *models.Mesh) (Error error) {

	// fetch matching meshDB
	if meshDB, ok := backRepoMesh.Map_MeshDBID_MeshDB[idx]; ok {
		_ = meshDB // to avoid unused variable error if there are no reverse to reset

		// insertion point for reverse pointers reset
		// end of insertion point for reverse pointers reset
	}

	return
}

